import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';  // 🔥 useSearchParams!

const SearchResults = () => {
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchParams] = useSearchParams();  // 🔥 Читаем параметры из URL

  // 🔥 ФИЛЬТРУЕМ туры по параметрам URL
  const filterTours = (allTours) => {
    let filtered = [...allTours];

    // Фильтр по стране
    const country = searchParams.get('country');
    if (country) {
      filtered = filtered.filter(tour => tour.country === country);
    }

    // Фильтр по городу вылета
    const departure = searchParams.get('departure');
    if (departure) {
      filtered = filtered.filter(tour => tour.departureCity === departure);
    }

    // Фильтр по ночам (парсим "6 - 14")
    const nights = searchParams.get('nights');
    if (nights) {
      const [minNights, maxNights] = nights.split(' - ').map(n => parseInt(n));
      filtered = filtered.filter(tour => {
        const tourNights = tour.nights.split('-').map(n => parseInt(n.trim()));
        return tourNights[0] >= minNights && tourNights[1] <= maxNights;
      });
    }

    return filtered;
  };

  // Загружаем и фильтруем туры
  useEffect(() => {
    fetch('/tours.json')
      .then(res => res.json())
      .then(allTours => {
        const filteredTours = filterTours(allTours);
        setTours(filteredTours);
        setLoading(false);
      })
      .catch(err => {
        console.error('Ошибка загрузки туров:', err);
        setLoading(false);
      });
  }, [searchParams]);  // 🔥 Перефильтровываем при изменении URL!

  if (loading) {
    return (
      <div className="TVSearchResults" style={{ margin: "0 auto", width: "1296px" }}>
        <div style={{ padding: '40px', textAlign: 'center', color: '#666' }}>
          Загрузка туров...
        </div>
      </div>
    );
  }

  return (
    <>
      <div className="TVSearchResults" style={{ margin: "0 auto", width: "1296px" }}>
        <div className="TVResultContentListWrapper">
          <div className="TVResultListView TVStyleTheme2">
            <div className="TVResultListViewBody TVResultContentList">
              
              {/* 🔥 ИНФО О ФИЛЬТРАХ */}
              <div style={{ 
                padding: '20px', 
                background: '#f8f9fa', 
                marginBottom: '20px',
                borderRadius: '8px',
                fontSize: '14px'
              }}>
                <strong>Найдено туров: {tours.length}</strong>
                {searchParams.toString() && (
                  <>
                    <br />
                    <small>Фильтры: {searchParams.toString()}</small>
                  </>
                )}
              </div>

              <div className="TVResultListViewList" id="tour-container">
                {tours.length === 0 ? (
                  <div style={{ 
                    gridColumn: '1 / -1', 
                    padding: '60px 20px', 
                    textAlign: 'center', 
                    color: '#666',
                    fontSize: '18px'
                  }}>
                    ❌ Туры не найдены по вашим критериям
                    <br />
                    <small style={{ fontSize: '14px', marginTop: '10px', display: 'block' }}>
                      Попробуйте другие фильтры
                    </small>
                  </div>
                ) : (
                  tours.map((tour) => (
                    <div key={tour.id} className="TVResultListViewItem" data-tour-id={tour.id}>
                      <div className="TVHotelResultItem">
                        <div className="TVHotelResulItemInfo">
                          <div className="TVHotelInfo">
                            <div className="TVResultItem">
                              <div className="TVResultItemImageWrapper TVSize-M">
                                <div className="TVResultItemImage">
                                  <div className="TVGallery TVResultItemGallery">
                                    <div className="TVGallContainer">
                                      <div className="TVGallList" style={{ width: "100%" }}>
                                        <div
                                          className="TVPhotoGalleryImage"
                                          style={{
                                            backgroundImage: `url('https://picsum.photos/400/200?random=${tour.id}')`,
                                            backgroundSize: "cover",
                                            height: "200px",
                                          }}
                                        />
                                      </div>
                                    </div>
                                  </div>
                                </div>
                              </div>
                              <div className="TVResultItemBodyWrapper TVResultItemBodyWrapperStretched">
                                <div className="TVResultItemHeader">
                                  <div className="TVResultItemPreTitle">
                                    <div className="stars-row">
                                      {[...Array(tour.stars)].map((_, i) => (
                                        <div key={i} className="TVHotelInfoStar TVColorYellow500">
                                          ★
                                        </div>
                                      ))}
                                    </div>
                                  </div>
                                  <div className="TVResultItemTitle">
                                    <Link className="TVHotelInfoTitleLink" to={`/tour/${tour.id}`}>
                                      {tour.title}
                                    </Link>
                                  </div>
                                  <div className="TVResultItemSubTitle">
                                    {tour.city}, {tour.country}
                                  </div>
                                  <div className="TVResultItemBeforeDescriptionWrapper">
                                    <div className="TVResultItemDescription">
                                      {tour.country === 'Турция' ? 'Городской отель в центре.' : 
                                       tour.country === 'Египет' ? 'Отель на первой линии.' : 
                                       'Комфортный отдых для всей семьи.'}
                                    </div>
                                  </div>
                                  <div className="TVResultItemFooter">
                                    <div className="TVResultItemNavButtons">
                                      <div className="TVResultNavButtons">
                                        <Link className="TVResultNavButton" to={`/tour/${tour.id}`}>
                                          Об отеле
                                        </Link>
                                        <div className="TVResultNavButton">Отзывы</div>
                                        <div className="TVResultNavButton">Карта</div>
                                        <Link className="TVResultNavButton" to={`/tour/${tour.id}`}>
                                          Номера
                                        </Link>
                                      </div>
                                    </div>
                                  </div>
                                  <div className="TVResultItemPrice">
                                    <div className="TVResultItemNewPrice">
                                      {tour.price.toLocaleString()} РУБ
                                    </div>
                                  </div>
                                </div>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      <style
        dangerouslySetInnerHTML={{
          __html: `
            .TVHide { display: none !important; }
            .TVResultNavButton {
              display: inline-block;
              padding: 5px 10px;
              margin-right: 5px;
              background: #eee;
              border-radius: 4px;
              cursor: pointer;
              text-decoration: none;
              color: #333;
            }
            .TVResultNavButton:hover {
              background: #ddd;
            }
          `,
        }}
      />
    </>
  );
};

export default SearchResults;
